const mongoose = require('mongoose');

async function queryBuilder(filter, projection, sort) {
    try {
        // Assuming you have a model named "User" in your MongoDB. Replace with the actual model name.
        const UserModel = mongoose.model('User', new mongoose.Schema()); 
        
        let query = UserModel.find();

        if (filter) {
            query = query.where(filter);
        }

        if (projection) {
            query = query.select(projection);
        }

        if (sort) {
            query = query.sort(sort);
        }
        
        const result = await query.exec(); // Execute the query
        return result;
    } catch (error) {
        console.log('Error in queryBuilder: ', error);
    }
}